export const 鎮宅西方 = (bi) => {
    const u = bi.u;
    const X = (x) => x;
    const Z = (z) => z - 4;
    const 線 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.42) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.26 * u;
        bi.A(X(x), Z(z), r);
        c.restore();
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.55, Z(z)).L(X(x1) - 0.55, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：三圈桿＋九圈陣
    桿(-9.6, 2.4, 6.9);
    桿(-9.7, 2.3, 8.8);
    桿(-9.7, 2.2, 10.6);
    for (const x of [-8.3, -3.9, 1.0])
        for (const z of [13.2, 15.0, 16.9])
            圈(x, z, 0.44);
    // 上雙匣（左寬右窄，中縫豎）
    線(p => p.M(X(-10.2), Z(18.8)).L(X(-4.6), Z(18.7)).L(X(-4.6), Z(23.3)).L(X(-10.2), Z(23.4)).L(X(-10.2), Z(18.8)));
    線(p => p.M(X(-10.0), Z(20.3)).L(X(-4.8), Z(20.2)), 0.38);
    線(p => p.M(X(-10.0), Z(21.8)).L(X(-4.8), Z(21.7)), 0.38);
    線(p => p.M(X(-3.9), Z(18.6)).L(X(-3.9), Z(23.9)));
    線(p => p.M(X(-3.3), Z(19.4)).L(X(2.6), Z(19.3)).L(X(2.6), Z(23.0)).L(X(-3.3), Z(23.1)).L(X(-3.3), Z(19.4)));
    線(p => p.M(X(-3.1), Z(21.2)).L(X(2.4), Z(21.1)), 0.38);
    // 中蛇帶滿幅（一筆三折，圓端）〔簡〕
    線(p => p.M(X(-3.6), Z(24.0))
        .C(X(-4.4), Z(24.1), X(-9.4), Z(24.2), X(-10.0), Z(24.4))
        .C(X(-11.0), Z(24.8), X(-11.0), Z(25.9), X(-10.0), Z(26.2))
        .L(X(2.0), Z(26.0))
        .C(X(3.0), Z(26.0), X(3.0), Z(27.4), X(2.0), Z(27.5))
        .L(X(-9.8), Z(27.7))
        .C(X(-10.8), Z(27.8), X(-10.8), Z(29.1), X(-9.8), Z(29.2))
        .L(X(1.6), Z(29.0)), 0.48);
    線(p => p.M(X(-9.9), Z(30.4)).L(X(2.2), Z(30.2)), 0.42);
    線(p => p.M(X(-4.2), Z(27.6)).L(X(-4.2), Z(30.3)), 0.38); // 中豎〔簡〕
    線(p => p.M(X(2.8), Z(25.9)).L(X(2.9), Z(30.6))); // 右欄
    // 下回匡：外匡含王骨與內蛇〔簡〕
    線(p => p.M(X(-10.6), Z(31.6)).L(X(3.2), Z(31.4)).L(X(3.4), Z(41.0)).L(X(-10.4), Z(41.4)).L(X(-10.6), Z(31.6)), 0.48);
    線(p => p.M(X(-8.6), Z(33.4)).L(X(1.4), Z(33.2)).L(X(1.4), Z(36.6)).L(X(-8.6), Z(36.8)).L(X(-8.6), Z(33.4)));
    線(p => p.M(X(-8.4), Z(35.0)).L(X(1.2), Z(34.9)), 0.38);
    線(p => p.M(X(-3.6), Z(33.3)).L(X(-3.6), Z(36.7)), 0.38); // 王骨
    // 內蛇（回匡下部，二折）
    線(p => p.M(X(-7.6), Z(37.6))
        .C(X(-8.4), Z(37.7), X(-8.4), Z(38.9), X(-7.6), Z(39.0))
        .L(X(-1.4), Z(38.8))
        .C(X(-0.6), Z(38.8), X(-0.6), Z(40.0), X(-1.4), Z(40.1))
        .L(X(-7.2), Z(40.3)), 0.45);
    // 撇足（匡外二撇）
    線(p => p.M(X(-9.6), Z(41.6))
        .C(X(-10.2), Z(42.2), X(-10.8), Z(42.6), X(-11.4), Z(42.8)), 0.45);
    線(p => p.M(X(2.4), Z(41.4))
        .C(X(3.0), Z(42.0), X(3.6), Z(42.4), X(4.2), Z(42.6)), 0.45);
};
